const sql = require('../models/db');
var Sequelize = require('sequelize');
var { Op } = require('sequelize');

const GridService = function (customer) {
  this.Score = customer.Score;
  this.Shoots = customer.Shoots;
  this.Time = customer.Time;
};


GridService.getByGridId = async ({gridId, accessLevel}) => {
  const result = await sql.GridAccessLevel.findAll({
    logging: console.log,
    order: [Sequelize.literal('col_order ASC')],
    where: {
      col_access_level: accessLevel,
      grid_id: gridId,
      access: true
    },
    include: [{
      model: sql.GridLayout,
      as: 'GridLayouts',
      where: {
        grid_id: gridId
      }
    }]
  })
  // result = result.map(grid => {
  //   return grid.GridLayouts.map(layout => {
  //     return {
  //       layout
  //     }
  //   })
  // })
  return result;
}

module.exports = GridService;

