module.exports = () => {
	const required = [
		"DB_HOST",
		"DB_PORT",
		"DB_USER",
		"DB_PASSWORD",
		"DB_NAME"
	];

	required.forEach((key) => {
		if (!process.env[key]) {
			throw new Error(`${key} is not defined`);
		}
	});

	return {
		HOST: process.env.DB_HOST,
		PORT: process.env.DB_PORT,
		PASSWORD: process.env.DB_PASSWORD,
		DB: process.env.DB_NAME,
		DBUser: process.env.DB_USER
	};
};

const Sequelize = require('sequelize');
module.exports = function(sequelize, DataTypes) {
  return sequelize.define('GridLayout', {
    id: {
      autoIncrement: true,
      autoIncrementIdentity: true,
      type: DataTypes.INTEGER,
      allowNull: false,
      primaryKey: true
    },
    field: {
      type: DataTypes.STRING,
      allowNull: true
    },
    filter: {
      type: DataTypes.STRING,
      allowNull: true
    },
    cellRenderer: {
      type: DataTypes.STRING,
      allowNull: true
    },
    hide: {
      type: DataTypes.STRING,
      allowNull: true
    },
    checkboxSelection: {
      type: DataTypes.STRING,
      allowNull: true
    },
    rowDrag: {
      type: DataTypes.STRING,
      allowNull: true
    },
    rowGroup: {
      type: DataTypes.STRING,
      allowNull: true
    },
    width: {
      type: DataTypes.INTEGER,
      allowNull: true
    },
    companyCode_name: {
      type: DataTypes.STRING,
      allowNull: true
    },
    divisionCode_name: {
      type: DataTypes.STRING,
      allowNull: true
    },
    col_pinned: {
      type: DataTypes.STRING,
      allowNull: true
    },
    col_order: {
      type: DataTypes.INTEGER,
      allowNull: true
    },
    user_id_fk: {
      type: DataTypes.INTEGER,
      allowNull: true
    },
    col_id: {
      type: DataTypes.STRING,
      allowNull: true
    },
    layout_name: {
      type: DataTypes.STRING,
      allowNull: true
    },
    grid_id: {
      type: DataTypes.STRING,
      allowNull: true
    },
    headerName: {
      type: DataTypes.STRING,
      allowNull: true
    },
    std_prod_id_fk: {
      type: DataTypes.INTEGER,
      allowNull: true
    },
    editable: {
      type: DataTypes.BOOLEAN,
      allowNull: true,
      defaultValue: true
    },
    cellEditor: {
      type: DataTypes.STRING,
      allowNull: true
    }
  }, {
    sequelize,
    tableName: 'GridLayout',

    timestamps: false,
    indexes: [
      {
        name: "GridLayout_pkey",
        unique: true,
        fields: [
          { name: "id" },
        ]
      },
      {
        name: "RFQLayout_pkey",
        unique: true,
        fields: [
          { name: "id" },
        ]
      },
    ]
  });
};

