ngOnInit(): void {

}
agInit(params: any): void {
  this.role = window['role']
  this.gridDomLayout = this.role === 'vendor' ? 'autoHeight' : 'normal';
  window['DialogData'] = false;
  window['dataWasChanged']
  window['dialog'] = this.dialog;
  window['onCellValueChanged'] = this.onCellValueChanged.bind(this);
  this.frameworkComponents = {
    'numericCellEditor': NumericEditor, 'autoCompelete': rfqAutocompleteComponent, 'datePicker': rfqDatepickerComponent, 'button': rfqButtonComponent,
    customTooltip: CustomTooltipComponent
  };
  this.params = params;
  this.allowedUserIdsToViewPrice = (this.configService.get('allowedUserIdsToViewPrice') as number[]) || [];
  this.allowAccessToSalesUsers = (this.configService.get('allowAccessToSalesUsers') as number[]) || [];
  this.enableSalesDetailEditing = !!this.configService.get('enableSalesDetailEditing');
  this.allowEditSalesUsersInDetailRenderer =
    (this.configService.get('allowEditSalesUsersInDetailRenderer') as number[]) || [];

  this.masterGridApi = params;
  this.rowId = params.node.id;
  // Load master column headers from config file
  this.masterColumnDefs = [...RFQ_COLUMN_HEADERS_CONFIG.columnDefs];
  this.masterColumnDefs = this.filterColumnsByRole(this.masterColumnDefs, this.role);
  // Preload FOB countries first, then load grid headers
  this.authService.getUserFromToken().then((user: any) => {
    this.currentUserId = user?.user_id ?? null;
    this.itemService.getFOBCountry().subscribe((countries: unknown) => {
      const countryList = Array.isArray(countries) ? countries : [];
      this.fobCountries = countryList
        .map((c: any) => c?.FOBCountry_title ?? c?.dataValues?.FOBCountry_title)
        .filter(Boolean);
      this.loadDetailColumnHeaders().subscribe((colHeaders: any[]) => {
        this.configureDetailColumnHeaders(colHeaders);
      });
    });
    // Factory → country map, used to pre-fill FOB Country when the user picks
    // a factory in the Name column. Non-fatal if it fails (we just don't auto-fill).
    this.aiSettings.getFactoryCountryMap().subscribe({
      next: res => { this.factoryCountryMap = res?.map ?? {}; },
      error: () => { this.factoryCountryMap = {}; },
    });
  });
  this.rowData = params.data.Vendors;

  this.defaultColDef = {
    sortable: true,
    editable: (params: any) => this.canCurrentSalesUserEditDetailCells(),
    resizable: true,
    filter: false,
  };

  this.rowData = params.data.Vendors;
  this.rowClassRules = {
    'responded': 'data.req_status == 2',
    'passed': 'data.req_status == 1',
    'empty': 'data.req_status == null'
  }
}

/** Detail columns from API (GridLayout / role access). Config migration later. */
private loadDetailColumnHeaders(): Observable<any[]> {
  return this.itemService.getGridHeader({ grid_id: 'rfq_detail' }) as Observable<any[]>;
}

