// READ-ONLY dry run: detect double-encoded (CP437/CP850 -> UTF-8) mojibake in
// GridLayout.field / headerName and show the recovered text. No writes.
const { Client } = require('pg');
const iconv = require('iconv-lite');

const SCHEMA = process.env.SCAN_SCHEMA || 'designflow_dev';

// Reverse the double-encode: glyph-string -> map glyphs back to their OEM byte
// values -> reinterpret those bytes as UTF-8.
function recover(str, codepage) {
  if (str == null) return null;
  const bytes = iconv.encode(str, codepage); // glyph -> OEM byte
  return bytes.toString('utf8');              // bytes -> real UTF-8
}
const hasNonAscii = s => s != null && /[^\x00-\x7F]/.test(s);
const isClean = s => s != null && !/�/.test(s) && /[一-鿿]/.test(s);

(async () => {
  const client = new Client({
    host: process.env.DB_HOST,
    port: Number(process.env.DB_PORT || 5432),
    user: process.env.DB_USER,
    password: process.env.DB_PASSWORD,
    database: process.env.DB_NAME,
    ssl: { rejectUnauthorized: false },
    connectionTimeoutMillis: 10000,
  });
  await client.connect();
  const { rows } = await client.query(
    `SELECT id, grid_id, "field", "headerName"
       FROM ${SCHEMA}."GridLayout"
      WHERE "field" ~ '[^\\x00-\\x7F]' OR "headerName" ~ '[^\\x00-\\x7F]'
      ORDER BY grid_id, col_order, id`
  );

  console.log(`Schema: ${SCHEMA}  |  candidate rows: ${rows.length}\n`);
  let recoverable437 = 0, recoverable850 = 0;
  for (const r of rows) {
    for (const col of ['field', 'headerName']) {
      const v = r[col];
      if (!hasNonAscii(v)) continue;
      const r437 = recover(v, 'cp437');
      const r850 = recover(v, 'cp850');
      if (isClean(r437)) recoverable437++;
      if (isClean(r850)) recoverable850++;
      console.log(`id=${r.id} grid=${r.grid_id} col=${col}`);
      console.log(`  stored : ${JSON.stringify(v)}`);
      console.log(`  cp437  : ${JSON.stringify(r437)}${isClean(r437) ? '  <= clean CJK' : ''}`);
      console.log(`  cp850  : ${JSON.stringify(r850)}${isClean(r850) ? '  <= clean CJK' : ''}`);
      console.log('');
    }
  }
  console.log(`Summary: cp437 cleanly recovers ${recoverable437}, cp850 cleanly recovers ${recoverable850}`);
  await client.end();
})().catch(e => { console.error(e.message); process.exit(1); });

