// Scans designflow_dev, designflow, designflow_sandbox for CP437->UTF-8
// double-encoded mojibake in GridLayout.field/headerName (read-only report),
// then REPAIRS only designflow_dev: backup -> transaction -> review -> commit.
const fs = require('fs');
const path = require('path');
const { Client } = require('pg');
const iconv = require('iconv-lite');

const SCAN_SCHEMAS = ['designflow_dev', 'designflow', 'designflow_sandbox'];
const FIX_SCHEMA = 'designflow_dev';
const COLS = ['field', 'headerName'];

const hasNonAscii = s => s != null && /[^\x00-\x7F]/.test(s);
const recover = s => (s == null ? null : iconv.encode(s, 'cp437').toString('utf8'));
const isCleanCJK = s => s != null && !/�/.test(s) && /[一-鿿]/.test(s);
// nbsp-only artifact like "┬á" recovers to a single NBSP/space — safe to fix too.
const isJustSpace = s => s != null && !/�/.test(s) && /^[\s ]+$/.test(s);

function newClient() {
  return new Client({
    host: process.env.DB_HOST, port: Number(process.env.DB_PORT || 5432),
    user: process.env.DB_USER, password: process.env.DB_PASSWORD,
    database: process.env.DB_NAME, ssl: { rejectUnauthorized: false },
    connectionTimeoutMillis: 10000,
  });
}

async function scan(client, schema) {
  const { rows } = await client.query(
    `SELECT id, grid_id, "field", "headerName" FROM ${schema}."GridLayout"
      WHERE "field" ~ '[^\\x00-\\x7F]' OR "headerName" ~ '[^\\x00-\\x7F]'
      ORDER BY grid_id, col_order, id`);
  const fixes = [];
  for (const r of rows) {
    for (const col of COLS) {
      const v = r[col];
      if (!hasNonAscii(v)) continue;
      const rec = recover(v);
      const ok = isCleanCJK(rec) || isJustSpace(rec);
      fixes.push({ id: r.id, grid_id: r.grid_id, col, old: v, recovered: rec, ok });
    }
  }
  return fixes;
}

(async () => {
  const client = newClient();
  await client.connect();

  // ---- 1. READ-ONLY SCAN OF ALL SCHEMAS ----
  const perSchema = {};
  for (const s of SCAN_SCHEMAS) {
    try { perSchema[s] = await scan(client, s); }
    catch (e) { perSchema[s] = { error: e.message }; }
  }
  console.log('===== SCAN REPORT (read-only) =====');
  for (const s of SCAN_SCHEMAS) {
    const f = perSchema[s];
    if (f.error) { console.log(`\n[${s}] ERROR: ${f.error}`); continue; }
    const fixable = f.filter(x => x.ok).length;
    console.log(`\n[${s}] candidate values: ${f.length}, cleanly recoverable: ${fixable}`);
    for (const x of f) {
      console.log(`  id=${x.id} grid=${x.grid_id} ${x.col}: ${JSON.stringify(x.old)} -> ${JSON.stringify(x.recovered)}${x.ok ? '' : '  (SKIP: not clean)'}`);
    }
  }

  // ---- 2. REPAIR designflow_dev ----
  const fixes = (perSchema[FIX_SCHEMA] || []).filter(x => x.ok && x.recovered !== x.old);
  console.log(`\n===== APPLYING FIX TO ${FIX_SCHEMA}: ${fixes.length} updates =====`);
  if (!fixes.length) { console.log('Nothing to fix.'); await client.end(); return; }

  const stamp = new Date().toISOString().replace(/[:.]/g, '-');
  const backupPath = path.join(__dirname, `mojibake-backup-${FIX_SCHEMA}-${stamp}.json`);
  fs.writeFileSync(backupPath, JSON.stringify(fixes.map(x => ({ id: x.id, col: x.col, old: x.old })), null, 2));
  console.log(`Backup written: ${backupPath}`);

  await client.query('BEGIN');
  try {
    for (const x of fixes) {
      await client.query(
        `UPDATE ${FIX_SCHEMA}."GridLayout" SET "${x.col}" = $1 WHERE id = $2`,
        [x.recovered, x.id]);
    }
    // Re-read for pre-commit review
    const ids = fixes.map(x => x.id);
    const { rows: after } = await client.query(
      `SELECT id, "field" FROM ${FIX_SCHEMA}."GridLayout" WHERE id = ANY($1) ORDER BY id`, [ids]);
    console.log('\n--- post-update, pre-commit values ---');
    for (const r of after) console.log(`  id=${r.id} field=${JSON.stringify(r.field)}`);
    await client.query('COMMIT');
    console.log('\nCOMMIT done.');
  } catch (e) {
    await client.query('ROLLBACK');
    console.error('ROLLED BACK:', e.message);
    process.exit(1);
  }
  await client.end();
})().catch(e => { console.error(e.message); process.exit(1); });

