    const fixable = f.filter(x => x.ok).length;
    console.log(`\n[${s}] candidate values: ${f.length}, cleanly recoverable: ${fixable}`);
    for (const x of f) {
      console.log(`  id=${x.id} grid=${x.grid_id} ${x.col}: ${JSON.stringify(x.old)} -> ${JSON.stringify(x.recovered)}${x.ok ? '' : '  (SKIP: not clean)'}`);
    }
  }

