  const fixes = (perSchema[FIX_SCHEMA] || []).filter(x => x.ok && x.recovered !== x.old);
  console.log(`\n===== APPLYING FIX TO ${FIX_SCHEMA}: ${fixes.length} updates =====`);
  if (!fixes.length) { console.log('Nothing to fix.'); await client.end(); return; }

  const stamp = new Date().toISOString().replace(/[:.]/g, '-');
  const backupPath = path.join(__dirname, `mojibake-backup-${FIX_SCHEMA}-${stamp}.json`);
  fs.writeFileSync(backupPath, JSON.stringify(fixes.map(x => ({ id: x.id, col: x.col, old: x.old })), null, 2));
  console.log(`Backup written: ${backupPath}`);

  await client.query('BEGIN');
  try {
    for (const x of fixes) {
      await client.query(
        `UPDATE ${FIX_SCHEMA}."GridLayout" SET "${x.col}" = $1 WHERE id = $2`,
        [x.recovered, x.id]);
    }
    // Re-read for pre-commit review
    const ids = fixes.map(x => x.id);
    const { rows: after } = await client.query(
      `SELECT id, "field" FROM ${FIX_SCHEMA}."GridLayout" WHERE id = ANY($1) ORDER BY id`, [ids]);
    console.log('\n--- post-update, pre-commit values ---');
    for (const r of after) console.log(`  id=${r.id} field=${JSON.stringify(r.field)}`);
    await client.query('COMMIT');
    console.log('\nCOMMIT done.');
  } catch (e) {
    await client.query('ROLLBACK');
    console.error('ROLLED BACK:', e.message);
    process.exit(1);
  }
  await client.end();
})().catch(e => { console.error(e.message); process.exit(1); });

