// READ-ONLY: scan every text column in every table across the app schemas for
// CP437/CP850->UTF-8 mojibake (detected by presence of box-drawing/block glyphs,
// which never occur in legitimate product data). Reports any hits with samples.
const { Client } = require('pg');

const SCHEMAS = ['designflow_dev', 'designflow', 'designflow_sandbox', 'public'];

// Box-drawing (U+2500–257F) + block elements (U+2580–259F).
let glyphs = '';
for (let c = 0x2500; c <= 0x259f; c++) glyphs += String.fromCharCode(c);
const PATTERN = '[' + glyphs + ']';

function newClient() {
  return new Client({
    host: process.env.DB_HOST, port: Number(process.env.DB_PORT || 5432),
    user: process.env.DB_USER, password: process.env.DB_PASSWORD,
    database: process.env.DB_NAME, ssl: { rejectUnauthorized: false },
    connectionTimeoutMillis: 15000,
  });
}

(async () => {
  const client = newClient();
  await client.connect();

  const { rows: cols } = await client.query(
    `SELECT table_schema, table_name, column_name
       FROM information_schema.columns
      WHERE table_schema = ANY($1)
        AND data_type IN ('character varying','text','character','citext')
      ORDER BY table_schema, table_name, column_name`, [SCHEMAS]);

  console.log(`Scanning ${cols.length} text columns across schemas: ${SCHEMAS.join(', ')}\n`);

  let totalHits = 0, hitColumns = 0, errors = 0;
  for (const c of cols) {
    const ref = `"${c.table_schema}"."${c.table_name}"."${c.column_name}"`;
    try {
      const q = `SELECT count(*)::int AS n,
                        min("${c.column_name}") FILTER (WHERE "${c.column_name}" ~ $1) AS sample
                   FROM "${c.table_schema}"."${c.table_name}"
                  WHERE "${c.column_name}" ~ $1`;
      const { rows } = await client.query(q, [PATTERN]);
      const n = rows[0].n;
      if (n > 0) {
        hitColumns++; totalHits += n;
        console.log(`HIT  ${ref}  rows=${n}  e.g. ${JSON.stringify(rows[0].sample)}`);
      }
    } catch (e) {
      errors++;
      console.log(`ERR  ${ref}  ${e.message}`);
    }
  }

  console.log(`\n===== RESULT =====`);
  console.log(`columns scanned : ${cols.length}`);
  console.log(`columns with mojibake : ${hitColumns}`);
  console.log(`total corrupted rows  : ${totalHits}`);
  console.log(`query errors : ${errors}`);
  if (hitColumns === 0) console.log('\n✅ No mojibake found anywhere. System is clean.');
  await client.end();
})().catch(e => { console.error(e.message); process.exit(1); });

