//   3. re-decoding the cp437 bytes as UTF-8 is VALID (no U+FFFD),
//   4. the result is strictly "less garbled" by a mojibake-marker score,
//   5. result !== original.
const fs = require('fs');
const path = require('path');
const { Client } = require('pg');
const iconv = require('iconv-lite');

const SCHEMA = 'designflow_dev';
const APPLY = process.env.APPLY === '1';

// Marker set: chars that appear in CP437 mojibake but ~never in clean product
// text — box-drawing/block (U+2500–259F), the cp437 Greek/symbol lead glyphs.
const MARKERS = new Set();
for (let c = 0x2500; c <= 0x259f; c++) MARKERS.add(c);
for (const c of 'ΣστµτΦΘΩαßΓπδ∞φε∩⌐¬½¼¡«»·°±÷√ⁿ²■▀▄▌▐░▒▓') MARKERS.add(c.codePointAt(0));
const score = s => [...s].reduce((n, ch) => n + (MARKERS.has(ch.codePointAt(0)) ? 1 : 0), 0);

const hasNonAscii = s => /[^\x00-\x7F]/.test(s);
const losslessCp437 = s => iconv.decode(iconv.encode(s, 'cp437'), 'cp437') === s;

function tryFix(v) {
  if (v == null || !hasNonAscii(v)) return null;
  if (!losslessCp437(v)) return null;                 // clean UTF-8 / real CJK -> skip
  const r = iconv.encode(v, 'cp437').toString('utf8');
  if (r === v || r.includes('�')) return null;   // not valid mojibake
  if (score(v) <= score(r)) return null;              // didn't get cleaner -> skip
  return r;
}

function newClient() {
  return new Client({
    host: process.env.DB_HOST, port: Number(process.env.DB_PORT || 5432),
    user: process.env.DB_USER, password: process.env.DB_PASSWORD,
    database: process.env.DB_NAME, ssl: { rejectUnauthorized: false },
    connectionTimeoutMillis: 20000,
  });
}

(async () => {
  const client = newClient();
  await client.connect();

  // single-column primary keys per table
  const { rows: pks } = await client.query(`
    SELECT tc.table_name, kcu.column_name
      FROM information_schema.table_constraints tc
      JOIN information_schema.key_column_usage kcu
        ON kcu.constraint_name = tc.constraint_name AND kcu.table_schema = tc.table_schema
     WHERE tc.constraint_type='PRIMARY KEY' AND tc.table_schema=$1`, [SCHEMA]);
  const pkByTable = {};
  for (const r of pks) (pkByTable[r.table_name] ??= []).push(r.column_name);

  const { rows: cols } = await client.query(`
    SELECT table_name, column_name FROM information_schema.columns
     WHERE table_schema=$1 AND data_type IN ('character varying','text','character','citext')
     ORDER BY table_name, column_name`, [SCHEMA]);
  const textColsByTable = {};
  for (const r of cols) (textColsByTable[r.table_name] ??= []).push(r.column_name);

  const planByTable = {};   // table -> [{pk, changes:{col:{old,new}}}]
  const colCounts = {};     // "table.col" -> count
  const samples = {};       // "table.col" -> [{old,new}]
  const skippedTables = [];
  let lossySkipped = 0;

  for (const [table, tcols] of Object.entries(textColsByTable)) {
    const pk = pkByTable[table];
    if (!pk || pk.length !== 1) { skippedTables.push(`${table} (no single-col PK)`); continue; }
    const pkCol = pk[0];
    const where = tcols.map(c => `"${c}" ~ '[^\\x00-\\x7F]'`).join(' OR ');
    const sel = [pkCol, ...tcols].map(c => `"${c}"`).join(', ');
    const { rows } = await client.query(`SELECT ${sel} FROM "${SCHEMA}"."${table}" WHERE ${where}`);
    for (const row of rows) {
      const changes = {};
      for (const c of tcols) {
        const v = row[c];
        if (v != null && hasNonAscii(v) && !losslessCp437(v)) lossySkipped++;
        const r = tryFix(v);
        if (r != null) {
          changes[c] = { old: v, new: r };
          const key = `${table}.${c}`;
          colCounts[key] = (colCounts[key] || 0) + 1;
          (samples[key] ??= []).length < 3 && samples[key].push({ old: v.slice(0, 80), new: r.slice(0, 80) });
        }
      }
      if (Object.keys(changes).length) (planByTable[table] ??= []).push({ pk: row[pkCol], pkCol, changes });
    }
  }

  const totalRows = Object.values(planByTable).reduce((n, a) => n + a.length, 0);
  const totalCells = Object.values(colCounts).reduce((n, v) => n + v, 0);

  console.log(`===== ${APPLY ? 'APPLY' : 'DRY RUN'} — ${SCHEMA} =====`);
  console.log(`columns to fix: ${Object.keys(colCounts).length}, rows: ${totalRows}, cells: ${totalCells}`);
  console.log(`non-ASCII values skipped as not-safely-recoverable (lossy): ${lossySkipped}`);
  if (skippedTables.length) console.log(`tables skipped (need manual handling): ${skippedTables.join(', ')}`);
  console.log(`\n--- per column ---`);
  for (const [key, n] of Object.entries(colCounts).sort((a, b) => b[1] - a[1])) {
    console.log(`  ${key}: ${n}`);
    for (const s of (samples[key] || [])) console.log(`      ${JSON.stringify(s.old)}  =>  ${JSON.stringify(s.new)}`);
  }

  const stamp = new Date().toISOString().replace(/[:.]/g, '-');
  const planPath = path.join(__dirname, `mojibake-repair-plan-${stamp}.json`);
  fs.writeFileSync(planPath, JSON.stringify(planByTable, null, 1));
  console.log(`\nFull plan/backup written: ${planPath}`);

  if (!APPLY) { console.log('\nDRY RUN only — no rows changed. Re-run with APPLY=1 to write.'); await client.end(); return; }

  console.log(`\nApplying...`);
  let done = 0;
  for (const [table, items] of Object.entries(planByTable)) {
    await client.query('BEGIN');
    try {
      for (const it of items) {
        const setCols = Object.keys(it.changes);
        const setSql = setCols.map((c, i) => `"${c}" = $${i + 1}`).join(', ');
        const vals = setCols.map(c => it.changes[c].new);
        await client.query(
          `UPDATE "${SCHEMA}"."${table}" SET ${setSql} WHERE "${it.pkCol}" = $${setCols.length + 1}`,
          [...vals, it.pk]);
        done++;
      }
      await client.query('COMMIT');
      console.log(`  ${table}: ${items.length} rows committed`);
    } catch (e) {
      await client.query('ROLLBACK');
      console.error(`  ${table}: ROLLED BACK — ${e.message}`);
    }
  }
  console.log(`\nDone. ${done} rows updated. Backup/plan: ${planPath}`);
  await client.end();
})().catch(e => { console.error(e.message); process.exit(1); });

