const textColsByTable = {};
for (const r of cols) (textColsByTable[r.table_name] ??= []).push(r.column_name);

// Value-based plan: table -> col -> Map(oldValue -> {new, rows})
// Updates are `SET col=new WHERE col=old`: no PK needed, idempotent, re-runnable.
const plan = {};
const colDistinct = {};    // "table.col" -> distinct values to fix
const colRows = {};        // "table.col" -> total rows affected
const samples = {};
let lossySkipped = 0;

for (const [table, tcols] of Object.entries(textColsByTable)) {
  const where = tcols.map(c => `"${c}" ~ '[^\\x00-\\x7F]'`).join(' OR ');
  const sel = tcols.map(c => `"${c}"`).join(', ');
  let rows;
  try { ({ rows } = await client.query(`SELECT ${sel} FROM "${SCHEMA}"."${table}" WHERE ${where}`)); }
  catch (e) { console.log(`  (skip ${table}: ${e.message})`); continue; }
  for (const row of rows) {
    for (const c of tcols) {
      const v = row[c];
      if (v != null && hasNonAscii(v) && !losslessCp437(v)) lossySkipped++;
      const r = tryFix(v);
      if (r == null) continue;
      const key = `${table}.${c}`;
      ((plan[table] ??= {})[c] ??= new Map());
      const m = plan[table][c];
      if (!m.has(v)) {
        m.set(v, r);
        colDistinct[key] = (colDistinct[key] || 0) + 1;
        (samples[key] ??= []).length < 3 && samples[key].push({ old: v.slice(0, 80), new: r.slice(0, 80) });
      }
      colRows[key] = (colRows[key] || 0) + 1;
    }
  }
}

const totalDistinct = Object.values(colDistinct).reduce((n, v) => n + v, 0);
const totalRows = Object.values(colRows).reduce((n, v) => n + v, 0);

console.log(`===== ${APPLY ? 'APPLY' : 'DRY RUN'} — ${SCHEMA} =====`);
console.log(`columns to fix: ${Object.keys(colDistinct).length}, distinct values: ${totalDistinct}, rows affected: ${totalRows}`);
console.log(`non-ASCII values skipped as not-safely-recoverable (lossy): ${lossySkipped}`);
console.log(`\n--- per column (rows / distinct values) ---`);
for (const [key, n] of Object.entries(colRows).sort((a, b) => b[1] - a[1])) {
  console.log(`  ${key}: ${n} rows / ${colDistinct[key]} distinct`);
  for (const s of (samples[key] || [])) console.log(`      ${JSON.stringify(s.old)}  =>  ${JSON.stringify(s.new)}`);
}

// Serialize plan (Maps -> arrays) as the backup/audit file.
const planOut = {};
for (const [t, cmap] of Object.entries(plan)) {
  planOut[t] = {};
  for (const [c, m] of Object.entries(cmap)) planOut[t][c] = [...m].map(([oldV, newV]) => ({ old: oldV, new: newV }));
}
const stamp = new Date().toISOString().replace(/[:.]/g, '-');
const planPath = path.join(__dirname, `mojibake-repair-plan-${stamp}.json`);
fs.writeFileSync(planPath, JSON.stringify(planOut, null, 1));
console.log(`\nFull plan/backup written: ${planPath}`);

if (!APPLY) { console.log('\nDRY RUN only — no rows changed. Re-run with APPLY=1 to write.'); await client.end(); return; }

console.log(`\nApplying...`);
let done = 0;
for (const [table, cmap] of Object.entries(plan)) {
  await client.query('BEGIN');
  try {
    let tRows = 0;
    for (const [c, m] of Object.entries(cmap)) {
      for (const [oldV, newV] of m) {
        const res = await client.query(
          `UPDATE "${SCHEMA}"."${table}" SET "${c}" = $1 WHERE "${c}" = $2`, [newV, oldV]);
        tRows += res.rowCount; done += res.rowCount;
      }
    }
    await client.query('COMMIT');
    console.log(`  ${table}: ${tRows} rows committed`);
  } catch (e) {
    await client.query('ROLLBACK');
    console.error(`  ${table}: ROLLED BACK — ${e.message}`);
  }
}
console.log(`\nDone. ${done} rows updated. Backup/plan: ${planPath}`);
await client.end();

