            `UPDATE "${SCHEMA}"."${table}" SET "${c}" = $1 WHERE "${c}" = $2`, [newV, oldV]);
          tRows += res.rowCount; done += res.rowCount;
        }
      }
      await client.query('COMMIT');
      console.log(`  ${table}: ${tRows} rows committed`);
    } catch (e) {
      await client.query('ROLLBACK');
      console.error(`  ${table}: ROLLED BACK — ${e.message}`);
    }
  }
  console.log(`\nDone. ${done} rows updated. Backup/plan: ${planPath}`);
  await client.end();
})().catch(e => { console.error(e.message); process.exit(1); });
